  1	import * as React from 'react';
  2	import { FieldLevelHelp } from '@odf/shared/generic/FieldLevelHelp';
  3	import { useDeepCompareMemoize } from '@odf/shared/hooks/deep-compare-memoize';
  4	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  5	import { getValidatedProp } from '@odf/shared/utils';
  6	import * as _ from 'lodash-es';
  7	import { Trans } from 'react-i18next';
  8	import {
  9	  FormGroup,
 10	  FormHelperText,
 11	  HelperText,
 12	  HelperTextItem,
 13	  TextInput,
 14	  ValidatedOptions,
 15	} from '@patternfly/react-core';
 16	import { validateConnectionName } from '../../constants';
 17	import { AzureConfig, ProviderNames } from '../../types';
 18	import { FileUploadInput } from './file-upload-input';
 19	import { KMSConfigureProps } from './providers';
 20	import { kmsConfigValidation, parseURL, isValidName } from './utils';
 21	
 22	export const AzureConfigure: React.FC<KMSConfigureProps> = ({
 23	  state,
 24	  dispatch,
 25	  className,
 26	}) => {
 27	  const { t } = useCustomTranslation();
 28	  const azureState = useDeepCompareMemoize(
 29	    state.kms.providerState,
 30	    true
 31	  ) as AzureConfig;
 32	  const azureStateClone: AzureConfig = React.useMemo(
 33	    () => _.cloneDeep(azureState),
 34	    [azureState]
 35	  );
 36	
 37	  const updateAzureState = React.useCallback(
 38	    (kmsConfig: AzureConfig) =>
 39	      dispatch({
 40	        type: 'securityAndNetwork/setKmsProviderState',
 41	        payload: kmsConfig,
 42	      }),
 43	    [dispatch]
 44	  );
 45	
 46	  const setServiceName = (name: string) => {
 47	    azureStateClone.name.value = name;
 48	    azureStateClone.name.valid = isValidName(name);
 49	    updateAzureState(azureStateClone);
 50	  };
 51	
 52	  const setAzureVaultURL = (address: string) => {
 53	    const trimAddress = address.trim();
 54	    const isValidAddress = parseURL(trimAddress) != null;
 55	    azureStateClone.azureVaultURL.value = trimAddress;
 56	    azureStateClone.azureVaultURL.valid = address !== '' && isValidAddress;
 57	    updateAzureState(azureStateClone);
 58	  };
 59	
 60	  const setClientID = (clientID: string) => {
 61	    azureStateClone.clientID.value = clientID;
 62	    azureStateClone.clientID.valid = clientID !== '';
 63	    updateAzureState(azureStateClone);
 64	  };
 65	
 66	  const setTenantID = (tenantId: string) => {
 67	    azureStateClone.tenantID.value = tenantId;
 68	    azureStateClone.tenantID.valid = tenantId !== '';
 69	    updateAzureState(azureStateClone);
 70	  };
 71	
 72	  const validateAzureVaultURLMessage =
 73	    azureState.azureVaultURL.value === ''
 74	      ? t('This is a required field')
 75	      : t('Please enter a valid Azure Vault URL');
 76	
 77	  const validateClientIDMessage =
 78	    azureState.clientID.value === ''
 79	      ? t('This is a required field')
 80	      : t('Please enter a valid Client ID');
 81	
 82	  const validateTenantIDMessage =
 83	    azureState.tenantID.value === ''
 84	      ? t('This is a required field')
 85	      : t('Please enter a valid Tenant ID');
 86	
 87	  React.useEffect(() => {
 88	    const hasHandled: boolean = kmsConfigValidation(
 89	      azureState,
 90	      ProviderNames.AZURE
 91	    );
 92	    if (azureState.hasHandled !== hasHandled) {
 93	      updateAzureState({ ...azureState, hasHandled });
 94	    }
 95	  }, [updateAzureState, azureState]);
 96	
 97	  const getValidatedNameProp = getValidatedProp(!azureState.name.valid);
 98	  const getValidatedVaultURLProp = getValidatedProp(
 99	    !azureState.azureVaultURL?.valid
100	  );
101	  const getValidatedClientIDProp = getValidatedProp(
102	    !azureState.clientID?.valid
103	  );
104	  const getValidatedTenantIDProp = getValidatedProp(
105	    !azureState.tenantID?.valid
106	  );
107	
108	  return (
109	    <>
110	      <FormGroup
111	        fieldId="kms-service-name"
112	        label={t('Connection name')}
113	        className={`${className}__form-body`}
114	        isRequired
115	      >
116	        <TextInput
117	          value={azureState.name.value}
118	          onChange={(_event, name: string) => {
119	            setServiceName(name);
120	          }}
121	          type="text"
122	          id="kms-service-name"
123	          name="kms-service-name"
124	          isRequired
125	          validated={getValidatedNameProp}
126	          data-test="kms-service-name-text"
127	        />
128	        <FormHelperText>
129	          <HelperText>
130	            <HelperTextItem variant={getValidatedNameProp}>
131	              {getValidatedNameProp === ValidatedOptions.default
132	                ? t(
133	                    'An unique name for the key management service within the project. Name must only include alphanumeric characters, "-", "_" or "."'
134	                  )
135	                : validateConnectionName(azureState.name.value, t)}
136	            </HelperTextItem>
137	          </HelperText>
138	        </FormHelperText>
139	      </FormGroup>
140	
141	      <FormGroup
142	        fieldId="azure-vault-url"
143	        label={t('Azure Vault URL')}
144	        labelHelp={
145	          <FieldLevelHelp>
146	            {t(
147	              'This URL is used to access and manage secrets, keys, and certificates stored in Azure Key Vault.'
148	            )}
149	          </FieldLevelHelp>
150	        }
151	        className={`${className}__form-body`}
152	        isRequired
153	      >
154	        <TextInput
155	          value={azureState.azureVaultURL?.value}
156	          onChange={(_event, address: string) => setAzureVaultURL(address)}
157	          type="url"
158	          id="azure-vault-url"
159	          name="azure-vault-url"
160	          isRequired
161	          validated={getValidatedVaultURLProp}
162	          data-test="azure-vault-url-text"
163	        />
164	        <FormHelperText>
165	          <HelperText>
166	            <HelperTextItem variant={getValidatedVaultURLProp}>
167	              {getValidatedVaultURLProp === ValidatedOptions.error &&
168	                validateAzureVaultURLMessage}
169	            </HelperTextItem>
170	          </HelperText>
171	        </FormHelperText>
172	      </FormGroup>
173	      <FormGroup
174	        fieldId="azure-client-id"
175	        label={t('Client ID')}
176	        labelHelp={
177	          <FieldLevelHelp>
178	            <Trans t={t}>
179	              <div>
180	                Client ID is the unique identifier of an application created in
181	                Azure AD (Active Directory).
182	              </div>
183	              <div className="pf-v6-u-mt-md">
184	                You can locate the client ID within Azure Active Directory by
185	                accessing the <strong>App registrations</strong> section.
186	              </div>
187	            </Trans>
188	          </FieldLevelHelp>
189	        }
190	        className={`${className}__form-body`}
191	        isRequired
192	      >
193	        <TextInput
194	          value={azureState.clientID?.value}
195	          onChange={(_event, clientID: string) => setClientID(clientID)}
196	          type="text"
197	          id="azure-client-id"
198	          name="azure-client-id"
199	          isRequired
200	          validated={getValidatedClientIDProp}
201	          data-test="azure-client-id-text"
202	        />
203	        <FormHelperText>
204	          <HelperText>
205	            <HelperTextItem variant={getValidatedClientIDProp}>
206	              {getValidatedClientIDProp === ValidatedOptions.error &&
207	                validateClientIDMessage}
208	            </HelperTextItem>
209	          </HelperText>
210	        </FormHelperText>
211	      </FormGroup>
212	      <FormGroup
213	        fieldId="azure-tenant-id"
214	        label={t('Tenant ID')}
215	        labelHelp={
216	          <FieldLevelHelp>
217	            <Trans t={t}>
218	              <div>
219	                The tenant ID determines the Azure AD instance where the
220	                application is hosted - it is the same as the organization ID.
221	                Also referred to as the Microsoft Entra tenant ID.
222	              </div>
223	              <div className="pf-v6-u-mt-md">
224	                You can find it by searching for{' '}
225	                <strong>Microsoft Entra ID</strong> in the Azure portal.
226	              </div>
227	            </Trans>
228	          </FieldLevelHelp>
229	        }
230	        className={`${className}__form-body`}
231	        isRequired
232	      >
233	        <TextInput
234	          value={azureState.tenantID?.value}
235	          onChange={(_event, tenantID: string) => setTenantID(tenantID)}
236	          type="text"
237	          id="azure-tenant-id"
238	          name="azure-tenant-id"
239	          isRequired
240	          validated={getValidatedTenantIDProp}
241	          data-test="azure-tenant-id-text"
242	        />
243	        <FormHelperText>
244	          <HelperText>
245	            <HelperTextItem variant={getValidatedTenantIDProp}>
246	              {getValidatedTenantIDProp === ValidatedOptions.error &&
247	                validateTenantIDMessage}
248	            </HelperTextItem>
249	          </HelperText>
250	        </FormHelperText>
251	      </FormGroup>
252	      <FileUploadInput
253	        key="azure-client-cert"
254	        id="clientCert"
255	        inputName={t('Certificate')}
256	        labelIcon={
257	          <FieldLevelHelp>
258	            {t(
259	              "Certificates serve as secrets to authenticate the application's identity when requesting a token. They are also known as public keys."
260	            )}
261	          </FieldLevelHelp>
262	        }
263	        helperText={t(
264	          'File must include a client certificate and a private key.'
265	        )}
266	        className={className}
267	        kmsState={azureState}
268	        kmsStateClone={azureStateClone}
269	        updateKmsState={updateAzureState}
270	      />
271	    </>
272	  );
273	};

