  1	import React from 'react';
  2	import { screen, render, fireEvent } from '@testing-library/react';
  3	import { AzureConfigure } from './azure-config';
  4	
  5	const state = {
  6	  kms: {
  7	    providerState: {
  8	      name: {
  9	        value: 'test-connection',
 10	        valid: true,
 11	      },
 12	      azureVaultURL: {
 13	        value: 'https://test.com',
 14	        valid: true,
 15	      },
 16	      clientID: {
 17	        value: 'azure-client-id1',
 18	        valid: true,
 19	      },
 20	      tenantID: {
 21	        value: 'azure-tenant-id1',
 22	        valid: true,
 23	      },
 24	      clientCert: {
 25	        id: 'clientCert',
 26	        value: '',
 27	      },
 28	    },
 29	  },
 30	};
 31	
 32	const dispatch = jest.fn();
 33	
 34	jest.mock('lodash-es', () => ({
 35	  ...jest.requireActual('lodash-es'),
 36	  cloneDeep: jest.fn((value) => value),
 37	}));
 38	
 39	describe('AzureConfigure component', () => {
 40	  it('renders correctly', () => {
 41	    const { container } = render(
 42	      <AzureConfigure state={state} dispatch={dispatch} />
 43	    );
 44	    const serviceName = container.querySelector(
 45	      '[data-test="kms-service-name-text"]'
 46	    ) as HTMLInputElement;
 47	    expect(serviceName).toBeInTheDocument();
 48	    expect(screen.getByText('Connection name')).toBeInTheDocument();
 49	    expect(serviceName.value).toBe('test-connection');
 50	    expect(
 51	      screen.getByText(
 52	        'An unique name for the key management service within the project. Name must only include alphanumeric characters, "-", "_" or "."'
 53	      )
 54	    ).toBeInTheDocument();
 55	    // eslint-disable-next-line testing-library/prefer-user-event
 56	    fireEvent.change(serviceName, {
 57	      target: { value: 'New Connection Name' },
 58	    });
 59	    expect(dispatch).toHaveBeenCalledWith({
 60	      type: 'securityAndNetwork/setKmsProviderState',
 61	      payload: {
 62	        ...state.kms.providerState,
 63	        name: {
 64	          value: 'New Connection Name',
 65	          valid: false,
 66	        },
 67	        hasHandled: false,
 68	      },
 69	    });
 70	
 71	    const azureVaultURL = container.querySelector(
 72	      '[data-test="azure-vault-url-text"]'
 73	    ) as HTMLInputElement;
 74	    expect(azureVaultURL).toBeInTheDocument();
 75	    expect(screen.getByText('Azure Vault URL')).toBeInTheDocument();
 76	    expect(azureVaultURL.value).toBe('https://test.com');
 77	    // eslint-disable-next-line testing-library/prefer-user-event
 78	    fireEvent.change(azureVaultURL, {
 79	      target: { value: 'https://new-test.com' },
 80	    });
 81	    expect(dispatch).toHaveBeenCalledWith({
 82	      type: 'securityAndNetwork/setKmsProviderState',
 83	      payload: {
 84	        ...state.kms.providerState,
 85	        azureVaultURL: {
 86	          value: 'https://new-test.com',
 87	          valid: true,
 88	        },
 89	      },
 90	    });
 91	
 92	    const clientID = container.querySelector(
 93	      '[data-test="azure-client-id-text"]'
 94	    ) as HTMLInputElement;
 95	    expect(clientID).toBeInTheDocument();
 96	    expect(screen.getByText('Client ID')).toBeInTheDocument();
 97	    expect(clientID.value).toBe('azure-client-id1');
 98	    // eslint-disable-next-line testing-library/prefer-user-event
 99	    fireEvent.change(clientID, { target: { value: 'new-azure-client-id' } });
100	    expect(dispatch).toHaveBeenCalledWith({
101	      type: 'securityAndNetwork/setKmsProviderState',
102	      payload: {
103	        ...state.kms.providerState,
104	        clientID: {
105	          value: 'new-azure-client-id',
106	          valid: true,
107	        },
108	      },
109	    });
110	
111	    const tenantID = container.querySelector(
112	      '[data-test="azure-tenant-id-text"]'
113	    ) as HTMLInputElement;
114	    expect(tenantID).toBeInTheDocument();
115	    expect(screen.getByText('Tenant ID')).toBeInTheDocument();
116	    expect(tenantID.value).toBe('azure-tenant-id1');
117	    // eslint-disable-next-line testing-library/prefer-user-event
118	    fireEvent.change(tenantID, { target: { value: 'new-azure-tenant-id' } });
119	    expect(dispatch).toHaveBeenCalledWith({
